#include <stdio.h>

void reverseArray(int *arr, int n) {
    int *start = arr;           // Pointer to first element
    int *end = arr + n - 1;      // Pointer to last element
    int temp;

    while (start < end) {
        // Swap elements using pointer dereferencing
        temp = *start;
        *start = *end;
        *end = temp;

        // Move pointers towards center
        start++;
        end--;
    }
}

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    int n = 5;
    int *p;

    printf("Original: ");
    for (p = arr; p < arr + n; p++)
        printf("%d ", *p);

    reverseArray(arr, n);

    printf("\nReversed: ");
    for (p = arr; p < arr + n; p++)
        printf("%d ", *p);

    return 0;
}

#include <stdio.h>

int stringLength(char *str) {
    int length = 0;
    char *ptr = str;  // Initialize pointer to first character

    // Traverse until null character
    while (*ptr != '\0') {
        length++;
        ptr++;  // Pointer arithmetic: move to next character
    }

    return length;
}

// Alternative using pointer arithmetic directly
int stringLength2(char *str) {
    char *start = str;
    while (*str != '\0') {
        str++;
    }
    return str - start;  // Pointer subtraction gives count
}

int main() {
    char s[] = "Hello World";
    printf("Length: %d\n", stringLength(s));
    printf("Length: %d\n", stringLength2(s));
    return 0;
}

#include <stdio.h>

int* binarySearch(int *low, int *high, int key) {
    int *mid;

    while (low <= high) {
        // Calculate mid using pointer arithmetic
        // Equivalent to: mid = low + (high - low) / 2
        mid = low + (high - low) / 2;

        if (*mid == key) {
            return mid;  // Found, return pointer to element
        }
        else if (*mid < key) {
            low = mid + 1;  // Search right half
        }
        else {
            high = mid - 1;  // Search left half
        }
    }

    return NULL;  // Not found
}

int main() {
    int arr[] = {2, 5, 8, 12, 16, 23, 38, 56, 72, 91};
    int n = 10;
    int key = 23;

    int *result = binarySearch(arr, arr + n - 1, key);

    if (result != NULL)
        printf("Found at index: %ld\n", result - arr);
    else
        printf("Not found\n");

    return 0;
}

#include <stdio.h>

int main() {
    char c = 'A';
    short s = 10;
    int i = 20;
    long l = 30;
    float f = 3.14;
    double d = 2.718;

    char *pc = &c;
    short *ps = &s;
    int *pi = &i;
    long *pl = &l;
    float *pf = &f;
    double *pd = &d;

    printf("Before increment:\n");
    printf("pc: %p, ps: %p, pi: %p\n", (void*)pc, (void*)ps, (void*)pi);
    printf("pf: %p, pd: %p\n", (void*)pf, (void*)pd);

    pc++; ps++; pi++; pl++; pf++; pd++;

    printf("\nAfter increment (address changes):\n");
    printf("pc: %p (+1 byte), ps: %p (+%zu bytes)\n", (void*)pc, (void*)ps, sizeof(short));
    printf("pi: %p (+%zu bytes), pl: %p (+%zu bytes)\n", (void*)pi, sizeof(int), (void*)pl, sizeof(long));
    printf("pf: %p (+%zu bytes), pd: %p (+%zu bytes)\n", (void*)pf, sizeof(float), (void*)pd, sizeof(double));

    // Demonstrate array traversal
    int arr[5] = {10, 20, 30, 40, 50};
    int *p = arr;

    printf("\nArray traversal:\n");
    for (int i = 0; i < 5; i++) {
        printf("Address: %p, Value: %d\n", (void*)(p + i), *(p + i));
    }

    return 0;
}
